// We restrict the entire universe to just these 3 options
enum class Plan {
    BASIC, PREMIUM, ENTERPRISE
}

fun main() {
    // We MUST pick from the rigid list
    val userPlan: Plan = Plan.PREMIUM
}

val userPlan = Plan.BASIC

// Look how clean this is! No risk of typos.
when (userPlan) {
    Plan.BASIC -> println("Welcome to standard.")
    Plan.PREMIUM -> println("Welcome VIP!")
    Plan.ENTERPRISE -> println("Welcome Boss!")
}
